"""
MKT Christ Commentary — Isaiah chapter 30
Run: python3 scripts/zc-christ-isaiah-30.py

Source data used:
- data/interlinear/isaiah.json
- data/translation/draft/mediating/isaiah.json

Key decisions in this range:
- v. 15: returning/rest = salvation; quietness/trust = strength — Matt 11:28-29; Heb 4
- v. 18: YHWH waits to be gracious, God of justice — shadow: Luke 15:20; 2 Pet 3:9
- v. 20: your Teacher (moreh) will not hide — shadow: John 6:45; 1 John 2:27
- v. 26: sevenfold light when YHWH heals — shadow: Rev 21:23; John 8:12
- v. 29: song in the night, Rock of Israel — shadow: 1 Cor 10:4; Easter
- v. 33: Topheth prepared for the king — shadow: Gehenna / Rev 20:10-15
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Non-destructive merge — existing entries are never overwritten, safe to re-run
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

ISAIAH = {
"30": {
"1": "<p>A revelation of God: woe to the rebellious children who carry out plans that are not from YHWH, adding sin to sin by going to Egypt — making an alliance without consulting YHWH's Spirit. This woe against the disobedient son is the anti-type of the obedient Son: Christ is the one who does nothing of his own accord but only what the Father shows him (John 5:19), who came not to do his own will but the will of the one who sent him (John 6:38). Philippians 2:8 frames his obedience explicitly: he humbled himself and became obedient to death. Israel adds sin to sin by consulting Egypt; Christ takes on Israel's sin to end the cycle.</p>",
"2": "<p>A revelation of God: they set out for Egypt without asking YHWH, taking refuge in Pharaoh's shadow — seeking security in human power rather than divine provision. The theology of misplaced refuge runs through the Psalms (Ps 20:7: some trust in chariots, some in horses, but we trust in YHWH; Ps 146:3: do not trust in princes, in a son of man who cannot save). Christ is the true refuge: Hebrews 6:18 (<em>we who flee to him for refuge</em>), the one in whose shadow nations find protection (Isa 51:16; Ps 91:1-2).</p>",
"3": "<p>A revelation of God: Pharaoh's protection will become Israel's shame; the shelter of Egypt's shadow will become humiliation. The anti-type is the cross: what appeared to be shame and defeat (1 Cor 1:23: <em>Christ crucified, a stumbling block to Jews and foolishness to Gentiles</em>) is the true shelter. The emperor who crucified appeared to be the protecting power; the crucified one proved to be the only one in whose shadow one is safe.</p>",
"4": "<p>A revelation of God: even to Zoan and Hanes the officials have gone — the extent of the alliance demonstrates the depth of Egypt's failure as a refuge. The farther one travels from YHWH's provision to seek human alternatives, the greater the eventual humiliation. This dynamic anticipates the prodigal son (Luke 15:13-14) whose journey into the far country ends in famine — the distance from the Father equals the depth of need.</p>",
"5": "<p>A revelation of God: all are put to shame by a people who neither help nor profit, bringing shame and also reproach. Egypt's help is <em>empty and vain</em> (<em>hebel wārîq</em> — vapor and emptiness). Every human savior-figure ultimately proves <em>hebel</em>: vapor, insubstantial. Only Christ is the substantive rescuer — the one who is not empty, whose help is not vapor, who actually delivers from the ultimate oppressor (Heb 2:14-15).</p>",
"6": "<p>A revelation of God: the oracle of the animals of the Negev — the dangerous journey south through lion country, carrying treasures on camels and donkeys to Egypt for help that does not profit. The irony: they risk lions and vipers to reach a land that cannot help. Christ inverts this: he leaves the safety of the Father to enter the territory of the Adversary (the wilderness temptation, Matt 4:1-11) not to seek refuge from it but to overcome it.</p>",
"7": "<p>A revelation of God: Egypt's help is utterly useless — <em>šaw' wĕhebel</em> — emptiness and vapor. The prophet names Egypt <em>Rahab who sits still</em> (<em>Rahab-hem-shebeth</em>) — the chaos monster who has no energy to act. Every substitute for YHWH proves to be a sleeping dragon, full of menacing appearance and empty of actual power. The gospel announces that only YHWH — incarnate in Christ — is the saving power that is not empty.</p>",
"8": "<p>A revelation of God: write this on a tablet and inscribe it in a book so it endures as a witness. YHWH directs the prophet to preserve the indictment permanently — divine words outlast the moment. This is the principle behind scripture itself: 2 Timothy 3:16 (all scripture is God-breathed and profitable); John 5:39 (the scriptures bear witness about Christ). The permanent record becomes the testimony that ultimately points to the one who fulfills what the rebellious generation refused.</p>",
"9": "<p>A revelation of God: a rebellious people, lying sons, sons who will not hear YHWH's instruction. The characterization of Israel as <em>bĕnê mĕrî</em> (rebellious sons) is the backdrop against which Christ as <em>the</em> faithful Son stands. Romans 5:19 frames the entire redemption in these terms: by one man's disobedience many were made sinners; by one man's obedience many will be made righteous. Christ is what the rebellious sons refused to be.</p>",
"10": "<p>A revelation of God: they say to the seers <em>do not see</em> and to the prophets <em>do not prophesy to us what is right; speak smooth things, prophesy illusions</em>. The demand for comfort over truth is the perennial human temptation. Paul warns that a time will come when people will not endure sound teaching but have itching ears and accumulate teachers to suit their own passions (2 Tim 4:3). Christ is the prophet who speaks what is right regardless of reception (John 8:40: I have told you the truth that I heard from God).</p>",
"11": "<p>A revelation of God: <em>leave the way, turn aside from the path, let us hear no more about the Holy One of Israel</em>. Rejecting the prophetic word is rejecting YHWH's identity as the Holy One. Jesus as the Holy One of God (John 6:69 — Peter's confession; Mark 1:24 — the demon's recognition) is precisely what the rebellious sons of Isaiah 30 refused. The rejection of Isaiah's word about the Holy One of Israel is the type of the rejection of the Holy One himself in the Gospel narrative.</p>",
"12": "<p>A revelation of God: because you despise this word and trust in oppression and perverseness — the reliance on human crooked dealing rather than divine word is the ground of judgment. The NT indictment of the same pattern: those who suppress the truth in unrighteousness (Rom 1:18) face the wrath of God. The rejection of straight paths for crooked ones is the trajectory that makes a Redeemer necessary — one who straightens the crooked (Luke 3:5: the crooked shall become straight).</p>",
"13": "<p>A revelation of God: this iniquity will be for you like a break in a high wall that bulges out and collapses suddenly. The metaphor of imminent structural collapse — the wall that appears solid but is already cracking — appears in Jesus' parable of the house on sand (Matt 7:26-27). Human structures built on anything other than YHWH's word collapse at the first storm. Christ is the cornerstone (Eph 2:20; 1 Pet 2:6) — the stone that prevents structural failure when built upon rightly.</p>",
"14": "<p>A revelation of God: broken like a potter's vessel, shattered so completely that not a sherd remains useful — no sherd to carry fire, no sherd to scoop water from the cistern. The total brokenness anticipates the complete ineffectiveness of all human remedies for sin. Christ alone is the one who can provide living water (John 4:10-14; 7:37-38) — not scooped from a cistern in a broken sherd but flowing from within the one who is himself the source.</p>",
"15": "<p>A shadow: <em>bĕšûb̄āh wānāḥat tiwwāšĕ'ûn</em> — in returning and rest you shall be saved; <em>bĕhašqēṭ ûb̄ebiṭḥāh</em> — in quietness and trust shall be your strength. This is the closest Isaiah gets to a statement of gospel in chapter 30. Jesus cites this verse's logic in Matthew 11:28-29: <em>come to me, all who are weary and heavy-laden, and I will give you rest; take my yoke upon you and learn from me, for I am gentle and lowly of heart, and you will find rest for your souls</em>. Hebrews 4:1-11 develops the same connection, reading the Sabbath rest as the eschatological rest that Christ inaugurates. Israel said <em>no</em> (v. 15b) to the rest; Christ says <em>come</em>.</p>",
"16": "<p>A revelation of God: Israel says <em>we will flee on horses</em> — and therefore they shall flee in defeat. The self-fulfilling irony of trusting in military speed: the very horses they trust in become the means of their rout. The NT framing: those who live by the sword die by the sword (Matt 26:52). Trusting human military capacity rather than YHWH results in experiencing that capacity turned against you. Christ's kingdom is not advanced by horses and chariots (Zech 9:9-10 — the king arrives on a donkey, a beast of peace, dismissing the war-horse).</p>",
"17": "<p>A revelation of God: one pursuing a thousand, five putting ten thousand to flight, until you are left as a flagstaff on a mountaintop — the exposed remnant, vulnerable, visible, alone. The decimated remnant standing alone is the anti-type of the exalted Christ on the cross — the one who was left alone (John 16:32: you will all be scattered, each to his own home, and leave me alone), the flagstaff of v. 17 becoming the lifted-up banner of Isaiah 11:10 and John 12:32.</p>",
"18": "<p>A shadow: therefore YHWH <em>waits to be gracious</em> to you (<em>yĕḥakkeh YHWH lĕḥonnĕkem</em>); he exalts himself to show mercy; blessed are all those who <em>wait for him</em> (<em>kol-ḥôkê lô</em>). The patient waiting of YHWH to be gracious is one of the most profound statements in Isaiah. 2 Peter 3:9 applies the same truth to the delay of Christ's return: he is not slow concerning his promises but patient, not willing that any should perish. The father running to meet the returning prodigal (Luke 15:20) is the narrative embodiment of YHWH who waits to be gracious. Blessed are those who wait for him — the Beatitudes re-express this (Matt 5:3-12).</p>",
"19": "<p>A shadow: the people in Zion shall weep no more; YHWH will surely be gracious at the sound of your cry — as soon as he hears it, he answers. The promise of immediate divine responsiveness to the cry of the distressed is the backdrop for Jesus' teaching on prayer: <em>ask and it will be given, seek and you will find</em> (Matt 7:7-11); the Father who gives good gifts to his children. Revelation 21:4 fulfills v. 19 completely: God will wipe every tear from their eyes and mourning shall be no more.</p>",
"20": "<p>A shadow: though the Lord give bread of adversity and water of affliction, <em>your Teacher will no longer hide himself, but your eyes will see your Teacher</em> (<em>wĕlō'-yikkānēp̄ 'ôd môrekā wĕhāyû 'êneykā rō'ôt 'et-môrekā</em>). The hiddenness of YHWH in the exile gives way to direct sight of the Teacher. John 1:14 is the fulfillment: <em>the Word became flesh and dwelt among us, and we have seen his glory</em>. John 6:45 cites the principle (they will all be taught by God, Isa 54:13) and applies it to coming to Christ. 1 John 2:27 — the anointing teaches you about all things — is the Spirit-mediated continuation of what the visible Teacher established. The Teacher who was hidden is now seen, and through the Spirit continues to teach.</p>",
"21": "<p>A shadow: your ears shall hear a word behind you saying <em>this is the way, walk in it</em> — divine guidance for every turning, left or right. Christ as the Way (John 14:6: <em>I am the way, the truth, and the life</em>) is the fulfillment of the guiding voice: the path behind, alongside, and ahead is Christ himself. The Spirit continues this guidance (John 16:13: the Spirit of truth will guide you into all truth). The voice behind you saying <em>this is the way</em> becomes the indwelling Spirit who leads the children of God (Rom 8:14).</p>",
"22": "<p>A revelation of God: then you will defile your silver-covered idols and gold-plated images, throwing them away as unclean — <em>wegone!</em> The repentance that follows the experience of the Teacher's presence includes spontaneous idol-rejection. The NT pattern is identical: when the Thessalonians received the gospel, they <em>turned to God from idols to serve the living and true God</em> (1 Thess 1:9). The sight of Christ makes idols not merely wrong but disgusting — <em>gēgone!</em> — begone! (cf. Phil 3:7-8: Paul counts all things as rubbish because of the surpassing worth of knowing Christ).</p>",
"23": "<p>A shadow: YHWH gives rain for the seed, the bread of the ground will be rich and plenteous, livestock will graze in large pastures. The eschatological agricultural abundance is the material face of covenant restoration. The NT reads this as the new creation: Romans 8:21 (creation itself will be freed from corruption); Revelation 22:2 (the tree of life yielding fruit every month). Christ as the bread of life (John 6:35) is the spiritual reality of which this material abundance is the type — the one who satisfies not just physical hunger but the hunger that no harvest can meet.</p>",
"24": "<p>A shadow: the oxen and donkeys will eat seasoned fodder — even the working animals share in the eschatological restoration. Creation-wide redemption is the scope: Romans 8:20-22 frames the created order as participating in the liberation from futility. Christ's lordship extends to all creation (Col 1:15-17: in him all things hold together; 1 Cor 15:28: God will be all in all). The working animals fed with fine fodder point to the comprehensive scope of the kingdom's shalom.</p>",
"25": "<p>A shadow: on every lofty mountain and every high hill, brooks running with water on the day of the great slaughter when the towers fall. The paradox — abundant water on the day of great slaughter — is the NT paradox of the cross: on the day of maximum devastation (the crucifixion), the water of life flows (John 19:34; cf. John 7:37-38). The tower that falls is the power of death; the water that runs freely is the Spirit poured out on Pentecost (Acts 2:17-18).</p>",
"26": "<p>A shadow: on the day YHWH binds up the brokenness of his people and heals the wound of their blow, the moon will be as bright as the sun and the sun will be sevenfold — as the light of seven days. The intensified light of the eschatological healing day is the backdrop for Revelation 21:23 and 22:5: the new Jerusalem has no need of sun or moon because the glory of God gives it light and the Lamb is its lamp. Christ's resurrection and the giving of the Spirit are the first rays of this sevenfold light; the consummation is its noon.</p>",
"27": "<p>A revelation of God: the name of YHWH comes from afar, burning with anger, in thick rising smoke, lips full of fury, tongue a devouring fire. The theophany of YHWH's wrath coming against Assyria in vv. 27-33 is cast in the language of the divine warrior (cf. Ps 18:7-15; Deut 33:2). Christ at his return is described in exactly these terms: Revelation 19:11-16 (the warrior whose eyes are like a flame of fire, whose robe is dipped in blood, from whose mouth comes a sharp sword to strike down the nations). The YHWH of Isaiah 30 and the returning Christ of Revelation 19 are the same divine warrior.</p>",
"28": "<p>A revelation of God: his breath like an overflowing stream, reaching to the neck, sifting the nations with the sieve of destruction, bridling the jaws of the peoples. The divine breath (<em>nišmāt YHWH</em>) as the instrument of judgment appears again in Isaiah 11:4 (breath of his lips slaying the wicked) and 2 Thessalonians 2:8 (Paul applies this to Christ destroying the lawless one with the breath of his mouth). The judgment that sifts the nations in Isaiah 30 is the final judgment that Christ executes at his return (Matt 25:31-46: sifting sheep from goats).</p>",
"29": "<p>A shadow: <em>you shall have a song as in the night when a holy feast is kept</em> — the night song of pilgrims going to the Rock of Israel (<em>Tsur Yisrael</em>). Paul identifies the Rock that accompanied Israel in the wilderness as Christ: <em>the Rock was Christ</em> (1 Cor 10:4). The night pilgrimage song becomes the Easter morning song — the night of weeping and crucifixion gives way to the dawn of resurrection (Ps 30:5: weeping may endure for a night, but joy comes in the morning). The journey to the Rock of Israel is the journey to Christ.</p>",
"30": "<p>A revelation of God: YHWH causes his majestic voice to be heard and the descending blow of his arm to be seen — in furious anger, devouring fire, cloudburst, storm, and hailstones against Assyria. The divine warrior acts with total, overwhelming force. The NT frames Christ's second advent in these theophanic terms (Rev 19:11-21; 1 Thess 4:16: the Lord descends from heaven with a cry of command). The blow of YHWH's arm against Assyria is the partial historical enactment of what will be complete at the consummation.</p>",
"31": "<p>A revelation of God: the Assyrians will be terror-stricken at the voice of YHWH when he strikes with his rod (<em>šēbeṭ mûsāh</em> — the rod of punishment). The Assyrian superpower is brought down not by human military force but by the divine voice alone. This is the consistent NT pattern of ultimate judgment: the word of Christ is the weapon (Rev 19:15 — the sword from his mouth strikes the nations; cf. 2 Thess 2:8). Human powers that seem invincible are unmade by the divine word.</p>",
"32": "<p>A revelation of God: every stroke of the appointed staff falls to the sound of tambourines and lyres — YHWH fights with a brandished arm. The paradox of joyful worship accompanying divine judgment on the enemy is the NT's <em>righteous wrath</em> theme: Revelation 18:20 (rejoice over Babylon, O heaven!) and 19:1-3 (the great hallelujah over the fall of the great harlot). The vindication of justice is cause for worship, not cold satisfaction — the songs of the redeemed celebrate the righteousness of divine judgment.</p>",
"33": "<p>A shadow: Topheth has long been prepared (<em>Tōp̄et min-'etmôl hûkān</em>) — it is made ready for the king; its pyre is deep and wide; YHWH's breath like a stream of sulfur kindles it. The burning place prepared for the Assyrian king (Sennacherib or the archetype of the destroyer) becomes in the NT the Gehenna of Matthew (5:22; 18:9; 23:33) and the lake of fire of Revelation 20:10-15: the fire prepared for the devil and his angels (Matt 25:41). Christ's warning about Gehenna in the Gospels stands on the foundation of Isaiah 30:33 — the burning place that YHWH prepared is the ultimate destination of all who align with the destroyer-king.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    v = sum(len(vs) for vs in ISAIAH.values())
    print(f'Isaiah 30 mkt-christ: {v} verses written.')

if __name__ == '__main__':
    main()
